function getText() {
  if (message && message.contact && message.contact.phone_number) {
    return String(message.contact.phone_number);
  }
  if (message && message.text) {
    return String(message.text).trim();
  }
  return "";
}

function cleanupInternal() {
  delete_context("_register_step");
}

function ask(prompt) {
  send_message({ text: prompt, parse_mode: "HTML" });
}

var steps = [
  {
    key: "register_full_name",
    prompt: get_context("param_name_prompt") || "Ro'yxatdan o'tish uchun ism va familiyangizni kiriting:",
    error: "Iltimos, ism va familiyani to'g'ri kiriting.",
    validate: function(value) { return value.length >= 3; }
  },
  {
    key: "register_phone",
    prompt: get_context("param_phone_prompt") || "Telefon raqamingizni yuboring yoki kiriting. Masalan: +998901234567",
    error: "Telefon raqamini +998901234567 formatida kiriting yoki kontakt yuboring.",
    validate: function(value) {
      var cleaned = value.replace(/[^\d+]/g, "");
      return /^\+?\d{9,15}$/.test(cleaned);
    },
    normalize: function(value) {
      var cleaned = value.replace(/[^\d+]/g, "");
      if (cleaned[0] !== "+") return "+" + cleaned;
      return cleaned;
    }
  },
  {
    key: "register_direction",
    prompt: get_context("param_direction_prompt") || "Qaysi yo'nalish yoki xizmatga qiziqasiz?",
    error: "Kamida 2 ta belgidan iborat javob kiriting.",
    validate: function(value) { return value.length >= 2; }
  },
  {
    key: "register_city",
    prompt: get_context("param_city_prompt") || "Qaysi filial, shahar yoki hudud sizga qulay?",
    error: "Iltimos, filial yoki hudud nomini kiriting.",
    validate: function(value) { return value.length >= 2; }
  },
  {
    key: "register_note",
    prompt: get_context("param_note_prompt") || "Qo'shimcha izoh bo'lsa yozing. Agar yo'q bo'lsa, '-' deb yuboring.",
    error: "Javobni qayta yuboring.",
    validate: function(value) { return value.length >= 1; },
    normalize: function(value) {
      if (value === "-") return "";
      return value;
    }
  }
];

var step = parseInt(get_context("_register_step") || "0", 10);
var answer = getText();

if (answer.toLowerCase() === "/cancel") {
  cleanupInternal();
  exit("cancelled");
}

if (step > 0) {
  var previous = steps[step - 1];
  var value = answer;
  if (previous.normalize) value = previous.normalize(value);
  if (!previous.validate(value)) {
    ask(previous.error + "\n\nBekor qilish uchun /cancel yuboring.");
    wait_for_input();
  }
  set_context(previous.key, value);
}

if (step >= steps.length) {
  var successMessage = get_context("param_success_message") || (
    "<b>Arizangiz qabul qilindi.</b>\n\n" +
    "👤 Ism: " + (get_context("register_full_name") || "") + "\n" +
    "📞 Telefon: " + (get_context("register_phone") || "") + "\n" +
    "🎯 Yo'nalish: " + (get_context("register_direction") || "") + "\n" +
    "📍 Filial/Hudud: " + (get_context("register_city") || "") + "\n" +
    "📝 Izoh: " + (get_context("register_note") || "-")
  );
  send_message({ text: successMessage, parse_mode: "HTML" });
  cleanupInternal();
  exit("completed");
}

ask(steps[step].prompt + "\n\nBekor qilish uchun /cancel yuboring.");
set_context("_register_step", String(step + 1));
wait_for_input();
